// Phase 5: 타입 시스템 기본 정의

/**
 * Primitive 타입
 */
export enum PrimitiveType {
  NUM = "num",
  STR = "str",
  BOOL = "bool",
  NULL = "null",
  UNKNOWN = "unknown",
}

/**
 * 타입 종류
 */
export type Type =
  | { kind: "primitive"; type: PrimitiveType }
  | { kind: "array"; elementType: Type }
  | { kind: "object"; properties: Map<string, Type> }
  | { kind: "fn"; paramTypes: Type[]; returnType: Type; capabilities?: Capability[]; typeParams?: string[] }
  | { kind: "union"; types: Type[] }
  | { kind: "never" }
  | { kind: "typevar"; name: string };  // Phase 5.5.4: TypeVar

/**
 * Phase 6: Capability 타입 정의
 */
export type CapabilityKind =
  | "read_file"
  | "write_file"
  | "network"
  | "spawn_process"
  | "execute_code"

export interface Capability {
  cap: CapabilityKind
  arg?: string
}

/**
 * 타입 검사 오류
 */
export interface TypeCheckError {
  message: string
  line?: number
  column?: number
  variable?: string
  expected?: Type
  actual?: Type
}

/**
 * 타입 검사 결과
 */
export interface TypeCheckResult {
  success: boolean
  errors: TypeCheckError[]
  types?: Map<string, Type>
}

/**
 * 제약 조건
 */
export interface Constraint {
  variable: string
  expectedType: Type
  actualType?: Type
  location?: { line: number; column: number }
}

/**
 * 충돌 보고서
 */
export interface ConflictReport {
  variable: string
  type1: Type
  type2: Type
  message: string
}

/**
 * 타입 호환성 확인
 */
export function typesCompatible(type1: Type, type2: Type): boolean {
  // Same type
  if (JSON.stringify(type1) === JSON.stringify(type2)) {
    return true
  }

  // Unknown type accepts anything (check BEFORE primitive check)
  if (type1.kind === "primitive" && type1.type === PrimitiveType.UNKNOWN) {
    return true
  }
  if (type2.kind === "primitive" && type2.type === PrimitiveType.UNKNOWN) {
    return true
  }

  // Primitive types
  if (type1.kind === "primitive" && type2.kind === "primitive") {
    return type1.type === type2.type
  }

  // Array types
  if (type1.kind === "array" && type2.kind === "array") {
    return typesCompatible(type1.elementType, type2.elementType)
  }

  // Union types - check if type2 is in union
  if (type2.kind === "union") {
    return type2.types.some((t) => typesCompatible(type1, t))
  }

  return false
}

/**
 * 타입 문자열 표현
 */
export function typeToString(type: Type): string {
  switch (type.kind) {
    case "primitive":
      return type.type

    case "array":
      return `array[${typeToString(type.elementType)}]`

    case "object":
      const props = Array.from(type.properties.entries())
        .map(([k, v]) => `${k}: ${typeToString(v)}`)
        .join(", ")
      return `object{${props}}`

    case "fn":
      const params = type.paramTypes.map(typeToString).join(", ")
      return `(${params}) -> ${typeToString(type.returnType)}`

    case "union":
      return type.types.map(typeToString).join(" | ")

    case "never":
      return "never"
  }
}

/**
 * 타입 파싱 (문자열 → Type)
 */
export function parseType(typeStr: string): Type {
  const trimmed = typeStr.trim()

  // Phase 5.5.4: 단일 문자 (T, U, A-Z, a-z) → TypeVar
  // parseParams()가 대문자를 보존하므로 "T" 형태로 들어옴
  const nonTypeAnnotations = ["num","str","bool","null","unknown"];
  if (/^[a-zA-Z]$/.test(trimmed) && !nonTypeAnnotations.includes(trimmed.toLowerCase())) {
    return { kind: "typevar", name: trimmed.toUpperCase() };
  }

  // Primitive types
  if (trimmed === "num") {
    return { kind: "primitive", type: PrimitiveType.NUM }
  }
  if (trimmed === "str") {
    return { kind: "primitive", type: PrimitiveType.STR }
  }
  if (trimmed === "bool") {
    return { kind: "primitive", type: PrimitiveType.BOOL }
  }
  if (trimmed === "null") {
    return { kind: "primitive", type: PrimitiveType.NULL }
  }

  // Array types
  if (typeStr.startsWith("array[") && typeStr.endsWith("]")) {
    const elementTypeStr = typeStr.substring(6, typeStr.length - 1)
    return {
      kind: "array",
      elementType: parseType(elementTypeStr),
    }
  }

  // Union types
  if (typeStr.includes(" | ")) {
    const types = typeStr.split(" | ").map((t) => parseType(t.trim()))
    return { kind: "union", types }
  }

  // Default to unknown
  return { kind: "primitive", type: PrimitiveType.UNKNOWN }
}

/**
 * 연산 결과 타입 결정
 */
export function getOperationResultType(
  op: string,
  leftType: Type,
  rightType: Type
): Type {
  // Primitive operations
  if (
    leftType.kind === "primitive" &&
    rightType.kind === "primitive"
  ) {
    const left = leftType.type
    const right = rightType.type

    // Numeric operations
    if (op === "Add") {
      if (left === PrimitiveType.NUM && right === PrimitiveType.NUM) {
        return { kind: "primitive", type: PrimitiveType.NUM }
      }
      // String concatenation
      if (left === PrimitiveType.STR || right === PrimitiveType.STR) {
        return { kind: "primitive", type: PrimitiveType.STR }
      }
    }

    if (
      (op === "Sub" || op === "Mul" || op === "Div" || op === "Mod") &&
      left === PrimitiveType.NUM &&
      right === PrimitiveType.NUM
    ) {
      return { kind: "primitive", type: PrimitiveType.NUM }
    }

    // Comparison operations
    if (
      op === "Eq" ||
      op === "Neq" ||
      op === "Lt" ||
      op === "Gt" ||
      op === "Lte" ||
      op === "Gte"
    ) {
      return { kind: "primitive", type: PrimitiveType.BOOL }
    }

    // Logical operations
    if (
      (op === "And" || op === "Or") &&
      left === PrimitiveType.BOOL &&
      right === PrimitiveType.BOOL
    ) {
      return { kind: "primitive", type: PrimitiveType.BOOL }
    }
  }

  // Array operations
  if (op === "Add" && leftType.kind === "array" && rightType.kind === "array") {
    // Array concatenation results in array
    return leftType
  }

  return { kind: "primitive", type: PrimitiveType.UNKNOWN }
}

/**
 * 타입 좁혀짐 (Type Narrowing)
 */
export function narrowType(type: Type, condition: Type): Type {
  // Union 타입에서 일부만 선택
  if (type.kind === "union") {
    for (const t of type.types) {
      if (typesCompatible(t, condition)) {
        return t
      }
    }
  }

  return type
}

/**
 * 타입 확대 (Type Widening)
 */
export function widenType(...types: Type[]): Type {
  if (types.length === 0) {
    return { kind: "primitive", type: PrimitiveType.UNKNOWN }
  }

  if (types.length === 1) {
    return types[0]
  }

  // 여러 타입을 Union으로 결합
  const uniqueTypes = types.filter(
    (t, i, arr) =>
      arr.findIndex((u) => JSON.stringify(u) === JSON.stringify(t)) === i
  )

  if (uniqueTypes.length === 1) {
    return uniqueTypes[0]
  }

  return { kind: "union", types: uniqueTypes }
}

/**
 * 타입 추론 기본 규칙
 */
export function inferTypeFromValue(value: any): Type {
  if (value === null || value === undefined) {
    return { kind: "primitive", type: PrimitiveType.NULL }
  }

  switch (typeof value) {
    case "number":
      return { kind: "primitive", type: PrimitiveType.NUM }
    case "string":
      return { kind: "primitive", type: PrimitiveType.STR }
    case "boolean":
      return { kind: "primitive", type: PrimitiveType.BOOL }
    default:
      return { kind: "primitive", type: PrimitiveType.UNKNOWN }
  }
}

/**
 * 함수 타입 생성
 */
export function createFunctionType(
  paramTypes: Type[],
  returnType: Type
): Type {
  return {
    kind: "fn",
    paramTypes,
    returnType,
  }
}

/**
 * 객체 타입 생성
 */
export function createObjectType(
  properties: Map<string, Type>
): Type {
  return {
    kind: "object",
    properties,
  }
}

/**
 * 배열 타입 생성
 */
export function createArrayType(elementType: Type): Type {
  return {
    kind: "array",
    elementType,
  }
}

/**
 * 기본 타입 미리 정의
 */
export const BUILTIN_TYPES = {
  NUM: { kind: "primitive" as const, type: PrimitiveType.NUM },
  STR: { kind: "primitive" as const, type: PrimitiveType.STR },
  BOOL: { kind: "primitive" as const, type: PrimitiveType.BOOL },
  NULL: { kind: "primitive" as const, type: PrimitiveType.NULL },
  UNKNOWN: { kind: "primitive" as const, type: PrimitiveType.UNKNOWN },
  NEVER: { kind: "never" as const },
}
